function [x,y] = fReadLecroy(fName)%% reads recroy scope txt data%%% Function read lecroy scope file% % Kei Nakamura% 2019/2/14 ver.1: created% %% mainaa = fileread(fName);bb = find(aa==13);x = zeros(numel(bb)-5,1); y = zeros(numel(bb)-5,1);for ii=6:numel(bb)    lin1 = aa(bb(ii-1)+2:bb(ii)-1);    cc = find(lin1==44);    % find comma    x(ii-5) = str2double(lin1(1:cc-1));    y(ii-5) = str2double(lin1(cc+1:end));end
